}

//删除
function delRow(row) {
    if (inPara.TableType == 'indi' ||
        inPara.TableType == 'slave') {
        Delete([row.id]).then((res) => {
            window.$message.info(res);
            GetAll().then((res) => {
                tableData.value = res;
                tableLoading.value = false;
            });
        });
    } else if (inPara.TableType == 'master') {
        DeleteSync(row.id).then((res) => {
            window.$message.info(res);
            GetAll().then((res) => {
                tableData.value = res;
                tableLoading.value = false;
                emit('pickRow', null);
            });
        });
    }
}

//选中行
